            text: { tag: 'lark_md', content: `**Amount**\n¥${params.amount}` },
          },
        ],
      },
      {
        tag: 'div',
        text: { tag: 'lark_md', content: `**Reason**\n${params.reason}` },
      },
      { tag: 'hr' },
      {
        tag: 'action',
        actions: [
          {
            tag: 'button',
            text: { tag: 'plain_text', content: 'Approve' },
